    return next(current["drafts"])

def judge(draft):
    return next(current["verdicts"])

def optimize(task, max_iters):
    feedback = None
    draft = None
    history = []
    for i in range(max_iters):
        draft = gen(task, feedback=feedback)
        verdict = judge(draft)
        history.append({
            "iter": i + 1,
            "draft": draft,
            "status": verdict["status"],
            "feedback": verdict["feedback"],
        })
        if verdict["status"] == "PASS":
            return {
                "final_draft": draft,
                "iters": i + 1,
                "passed": True,
                "history": history,
            }
        feedback = verdict["feedback"]
    return {
        "final_draft": draft,
        "iters": max_iters,
        "passed": False,
        "history": history,
    }

